def process_graph(graph_data):
    # Work on a copy to avoid mutating the input graph
    graph_copy = graph_data.copy()

    # Helper to find node ID by its 'name' attribute
    def get_node_id_by_name(name):
        for node_id, node_attrs in graph_copy.nodes(data=True):
            if node_attrs.get('name') == name:
                return node_id
        return None

    # Remove the specified PORT node if it exists
    target_name = "ju1.a2.m2.s3c7.p1"
    target_id = get_node_id_by_name(target_name)
    if target_id is not None and graph_copy.has_node(target_id):
        graph_copy.remove_node(target_id)

    # Find the parent node "ju1.a2.m2.s3c7"
    parent_id = get_node_id_by_name("ju1.a2.m2.s3c7")
    if parent_id is None or not graph_copy.has_node(parent_id):
        # Parent not found – return empty list and the updated graph
        updated_graph = nx.readwrite.json_graph.node_link_data(graph_copy)
        return {
            "type": "list",
            "data": [],
            "updated_graph": updated_graph
        }

    # Determine if an edge is of type RK_CONTAINS (handles str or list)
    def edge_is_contains(edge_data):
        etype = edge_data.get('type')
        if isinstance(etype, list):
            return 'RK_CONTAINS' in etype
        return etype == 'RK_CONTAINS'

    # Gather direct children via outgoing RK_CONTAINS edges
    child_ids = []
    for _, nbr, edata in graph_copy.out_edges(parent_id, data=True):
        if edge_is_contains(edata):
            child_ids.append(nbr)

    # Compute total physical capacity for a subtree rooted at a given node
    def subtree_port_capacity(root_id):
        total = 0
        stack = [root_id]
        visited = set()
        while stack:
            cur = stack.pop()
            if cur in visited:
                continue
            visited.add(cur)
            cur_attrs = graph_copy.nodes[cur]
            cur_type = cur_attrs.get('type', [])
            # If this node is a PORT, add its capacity
            if isinstance(cur_type, list) and 'EK_PORT' in cur_type:
                total += cur_attrs.get('physical_capacity_bps', 0)
            # Traverse containment edges outward
            for _, nbr, edata in graph_copy.out_edges(cur, data=True):
                if edge_is_contains(edata):
                    stack.append(nbr)
        return total

    # Build list of (child_name, total_capacity) tuples
    result = []
    for child_id in child_ids:
        child_name = graph_copy.nodes[child_id].get('name', str(child_id))
        cap = subtree_port_capacity(child_id)
        result.append((child_name, cap))

    # Sort descending by capacity
    result.sort(key=lambda x: x[1], reverse=True)

    # Provide updated graph in node-link JSON format
    updated_graph = nx.readwrite.json_graph.node_link_data(graph_copy)

    return {
        "type": "list",
        "data": result,
        "updated_graph": updated_graph
    }

